package manifest

// Manifest is the v1 schema for `.aienv.yaml`.
//
// NOTE: This is a strict schema. Unknown keys are rejected at load time,
// except for forward-compat extension keys that start with `x-`.
type Manifest struct {
	Version int `yaml:"version"`

	Canonical CanonicalSource `yaml:"canonical"`

	// Targets is an optional list of tool targets to compile to. Empty means
	// "no targets" (a valid state for a workspace that is not yet configured).
	Targets []string `yaml:"targets,omitempty"`

	// Scope declares where the rendered config is intended to apply for the
	// target tools. v1 accepts: user, project, global.
	Scope string `yaml:"scope,omitempty"`

	Cache CacheConfig `yaml:"cache,omitempty"`

	Adapters []AdapterDecl `yaml:"adapters,omitempty"`

	// TrustedSHA is the project-level trust anchor. It mirrors `canonical.commit`
	// and is committed to git so CI can fail closed on drift. See plan decision #9.
	TrustedSHA string `yaml:"trusted_sha,omitempty"`

	Trust TrustConfig `yaml:"trust,omitempty"`
}

type CanonicalSource struct {
	// Exactly one of URL or LocalPath must be set.
	URL       string `yaml:"url,omitempty"`
	LocalPath string `yaml:"local_path,omitempty"`

	// Ref is an optional git ref name (branch, tag) used at init time before
	// resolving to Commit.
	Ref string `yaml:"ref,omitempty"`

	// Commit is the pinned git commit SHA (40 hex). Pinning is the default.
	Commit string `yaml:"commit,omitempty"`
}

type CacheConfig struct {
	// Override, if set, overrides the default cache root. This may be used for
	// workspace-local cache storage.
	Override string `yaml:"override,omitempty"`
}

type AdapterDecl struct {
	Name string `yaml:"name"`

	// Source may point to an out-of-tree adapter implementation. Bundled
	// adapters use an implicit source.
	Source string `yaml:"source,omitempty"`
}

type TrustConfig struct {
}

package manifest

import (
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"regexp"
	"strings"

	"github.com/goccy/go-yaml"
)

type LoadOptions struct {
	// NonInteractive enforces the CI-safe invariant: if `canonical.commit` is
	// set, `trusted_sha` must also be set.
	NonInteractive bool
}

var (
	ErrInvalidManifest = errors.New("invalid manifest")

	reHex40 = regexp.MustCompile(`\A[0-9a-f]{40}\z`)
)

// MaxManifestSize is the maximum allowed manifest file size (1 MiB).
const MaxManifestSize = 1 << 20

func LoadFile(path string, opts LoadOptions) (*Manifest, error) {
	info, err := os.Stat(path)
	if err != nil {
		return nil, fmt.Errorf("manifest: stat %q: %w", path, err)
	}
	if info.Size() > MaxManifestSize {
		return nil, fmt.Errorf("%w: manifest exceeds %d bytes (got %d)", ErrInvalidManifest, MaxManifestSize, info.Size())
	}
	b, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("manifest: read %q: %w", path, err)
	}

// Command aienvs is the entry point for the aienvs CLI.
//
// aienvs keeps AI-agent configuration for multiple tools in sync from a
// single Git-backed manifest. See the repository README and
// docs/plans/2026-04-21-001-feat-aienvs-workspace-cli-plan.md for the
// architecture.
//
// This file is an intentional stub until unit 16 (cobra + fang wiring)
// lands. It exists now so every later unit can be wired through `go run`
// and so the Go module has a buildable main package.
package main

import (
	"fmt"
	"os"
)

// version is overwritten at build time via -ldflags.
var version = "dev"

func main() {
	os.Exit(run(os.Args[1:]))
}

func run(args []string) int {
	if len(args) == 1 && (args[0] == "--version" || args[0] == "-v") {
		_, _ = fmt.Fprintln(os.Stdout, version)
		return 0
	}
	_, _ = fmt.Fprintln(os.Stderr, "aienvs: CLI surface not yet implemented (unit 16).")
	_, _ = fmt.Fprintln(os.Stderr, "       See docs/plans/2026-04-21-001-feat-aienvs-workspace-cli-plan.md")
	return 2
}

