		{"0123456789ABCDEF0123456789abcdef01234567", false}, // uppercase rejected
		{"0123456789abcdef0123456789abcdef0123456", false},  // 39 chars
		{"0123456789abcdef0123456789abcdef012345678", false}, // 41 chars
