	t.Parallel()

	base := LogEntry{
		TSRaw:    "2026-05-01T12:00:00Z",
		Op:       OpTrust,
		URL:      "https://github.com/example/repo",
		SHA:      "0123456789abcdef0123456789abcdef01234567",
