// Package cli holds cobra command factories for the aienvs CLI. Unit 6
// introduces the first subcommand tree (`aienvs trust`); Unit 16 will wire
// the full root command + fang styling.
package cli

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"os"
	"os/exec"
	"os/user"
	"path/filepath"
