224	// validatePendingEntry checks structural invariants.
225	func validatePendingEntry(e PendingEntry) error {
226		if e.URL == "" {
227			return errors.New("trust: pending: url is required")
228		}
229		if e.TSRaw == "" {
230			return errors.New("trust: pending: ts is required")
231		}
232		if !IsSHA40(e.NewSHA) {
233			return fmt.Errorf("trust: pending: new_sha must be 40-hex, got %q", e.NewSHA)
234		}
235		if e.OldSHA != "" && !IsSHA40(e.OldSHA) {
236			return fmt.Errorf("trust: pending: old_sha must be empty or 40-hex, got %q", e.OldSHA)
237		}
238		return nil
239	}
240	
241	// marshalPendingEntry serializes e to one JSONL line including trailing
242	// newline.
243	func marshalPendingEntry(e PendingEntry) ([]byte, error) {
244		if e.TSRaw == "" && !e.TS.IsZero() {
245			e.TSRaw = e.TS.UTC().Format(time.RFC3339)
246		}
247		b, err := json.Marshal(e)
248		if err != nil {
249			return nil, fmt.Errorf("trust: marshal pending: %w", err)
250		}
251		return append(b, '\n'), nil
252	}
253	
254	// parsePendingLines decodes pending.jsonl.
255	func parsePendingLines(r *os.File, path string) ([]PendingEntry, error) {
256		sc := bufio.NewScanner(r)
257		sc.Buffer(make([]byte, 0, 64<<10), 1<<20)
258	
259		var out []PendingEntry
260		lineNo := 0
261		for sc.Scan() {
262			lineNo++
263			line := sc.Bytes()
264			if len(line) == 0 {
265				continue
266			}
267			var e PendingEntry
268			if err := json.Unmarshal(line, &e); err != nil {
269				return nil, fmt.Errorf("trust: parse pending %s line %d: %w", path, lineNo, err)
270			}
271			if e.TSRaw != "" {
272				if t, err := time.Parse(time.RFC3339, e.TSRaw); err == nil {
273					e.TS = t
274				}
275			}
276			out = append(out, e)
277		}
278		if err := sc.Err(); err != nil {
279			return nil, fmt.Errorf("trust: scan pending %s: %w", path, err)
280		}
281		return out, nil

