188	func newTrustStatusCmd(deps TrustDeps) *cobra.Command {
189		var asJSON bool
190		cmd := &cobra.Command{
191			Use:   "status",
192			Short: "Show per-URL trust state",
193			RunE: func(cmd *cobra.Command, _ []string) error {
194				s, err := resolveTrustStore(deps)
195				if err != nil {
196					return err
197				}
198				m, err := s.Fold()
199				if err != nil {
200					return err
201				}
202				out := outWriter(deps, cmd)
203				return printStatus(out, m, asJSON)
204			},
205		}
206		cmd.Flags().BoolVar(&asJSON, "json", false, "emit JSON instead of text")
207		return cmd
208	}
209	
210	type statusRow struct {
211		URL        string    `json:"url"`
212		CurrentSHA string    `json:"current_sha"`
213		LastOp     trust.Op  `json:"last_op"`
214		LastOpTS   time.Time `json:"last_op_ts"`
215		Revoked    bool      `json:"revoked"`
216	}
217	
218	func printStatus(out io.Writer, m map[string]trust.State, asJSON bool) error {
219		rows := make([]statusRow, 0, len(m))
220		for url, st := range m {
221			rows = append(rows, statusRow{
222				URL:        url,
223				CurrentSHA: st.CurrentSHA,
224				LastOp:     st.LastOp,
225				LastOpTS:   st.LastOpTS,
226				Revoked:    st.Revoked,
227			})
228		}
229		slices.SortFunc(rows, func(a, b statusRow) int { return cmp.Compare(a.URL, b.URL) })
230	
231		if asJSON {
232			enc := json.NewEncoder(out)
233			enc.SetIndent("", "  ")
234			return enc.Encode(rows)
235		}
236		for _, r := range rows {
237			_, _ = fmt.Fprintf(out, "%s\t%s\t%s\t%s\n", r.URL, shortSHAOrDash(r.CurrentSHA), r.LastOp, r.LastOpTS.Format(time.RFC3339))
238		}
239		return nil
240	}
